import React, { useCallback, useEffect, useMemo, useState } from 'react';
import api, { expenseService, seasonService } from '../../services/api';
import '../../styles/dashboard.css';
import '../../styles/accountant/accountant-expenses.css';
import { pushToast } from "../../utils/toastBridge";
const emptyForm = {
  season_id: '',
  category_id: '',
  amount: '',
  expense_date: '',
  note: ''
};
const formatCurrency = value => {
  const numberValue = Number(value || 0);
  return `${numberValue.toLocaleString('vi-VN')} �`;
};
const formatDate = value => {
  if (!value) return '-';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return value;
  return new Intl.DateTimeFormat('vi-VN', {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    timeZone: 'Asia/Ho_Chi_Minh'
  }).format(date);
};
const getSeasonLabel = season => {
  if (!season) return '-';
  const seasonName = season.season_name || `Mùa vụ ${season.season_id}`;
  return seasonName;
};
const AccountantExpenses = () => {
  const [seasons, setSeasons] = useState([]);
  const [expenseCategories, setExpenseCategories] = useState([]);
  const [expenses, setExpenses] = useState([]);
  const [seasonSummary, setSeasonSummary] = useState({
    season_id: null,
    season_name: '',
    total_expense: 0
  });
  const [productImports, setProductImports] = useState([]);
  const [importsTotal, setImportsTotal] = useState(0);
  const [selectedSeasonId, setSelectedSeasonId] = useState('');
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [categorySaving, setCategorySaving] = useState(false);
  const [categoryError, setCategoryError] = useState('');
  const [categorySuccess, setCategorySuccess] = useState('');
  const [showModal, setShowModal] = useState(false);
  const [showCategoryModal, setShowCategoryModal] = useState(false);
  const [form, setForm] = useState(emptyForm);
  const [categoryName, setCategoryName] = useState('');
  const [editingCategoryId, setEditingCategoryId] = useState(null);
  const [editingCategoryName, setEditingCategoryName] = useState('');
  useEffect(() => {
    if (selectedSeasonId) {
      fetchSeasonData(selectedSeasonId);
    }
  }, [selectedSeasonId]);
  const seasonOptions = useMemo(() => {
    return seasons.map(season => ({
      id: season.season_id,
      label: getSeasonLabel(season)
    }));
  }, [seasons]);
  const currentSeason = useMemo(() => {
    return seasons.find(season => String(season.season_id) === String(selectedSeasonId)) || null;
  }, [seasons, selectedSeasonId]);
  const fetchInitialData = useCallback(async () => {
    try {
      setLoading(true);
      const [seasonsRes, categoriesRes] = await Promise.all([seasonService.getAllSeasons(), expenseService.getExpenseCategories()]);
      const seasonList = seasonsRes?.data?.data || [];
      setSeasons(seasonList);
      setExpenseCategories(categoriesRes?.data?.data || []);
      const firstSeasonId = seasonList[0]?.season_id;
      if (firstSeasonId) {
        setSelectedSeasonId(String(firstSeasonId));
        setForm(prev => ({
          ...prev,
          season_id: String(firstSeasonId)
        }));
        await fetchSeasonData(firstSeasonId);
      }
    } catch (err) {
      pushToast({
        title: "Th�t b�i",
        message: err?.response?.data?.message || 'Không tải �ược dữ li�!u chi phí',
        type: "error"
      });
    } finally {
      setLoading(false);
    }
  }, []);
  useEffect(() => {
    fetchInitialData();
  }, [fetchInitialData]);
  const fetchSeasonData = async seasonId => {
    try {
      const [expensesRes, summaryRes] = await Promise.all([expenseService.getExpensesBySeasonId(seasonId), expenseService.getTotalExpenseBySeason(seasonId)]);
      setExpenses(expensesRes?.data?.data || []);
      setSeasonSummary(summaryRes?.data?.data || {
        season_id: seasonId,
        season_name: '',
        total_expense: 0
      });
      // Fetch stock imports within season date range
      try {
        let season = seasons.find(s => String(s.season_id) === String(seasonId));
        if (!season) {
          const seasonRes = await seasonService.getSeasonById(seasonId);
          season = seasonRes?.data?.data || null;
        }
        const startDate = season?.start_date || null;
        const endDate = season?.actual_harvest || season?.expected_harvest || null;
        const params = new URLSearchParams();
        if (startDate) params.append('startDate', startDate);
        if (endDate) params.append('endDate', endDate);
        const importsRes = await api.get(`/inventory/imports?${params.toString()}`);
        const imports = importsRes?.data?.data || [];

        // Aggregate imports by product
        const grouped = {};
        imports.forEach(it => {
          const pid = it.product_id;
          if (!grouped[pid]) grouped[pid] = {
            product_id: pid,
            product_code: it.product_code,
            product_name: it.product_name,
            unit: it.unit,
            total_quantity: 0,
            total_amount: 0
          };
          grouped[pid].total_quantity += Number(it.quantity || 0);
          grouped[pid].total_amount += Number(it.total_amount || 0);
        });
        const groupedList = Object.values(grouped);
        setProductImports(groupedList);
        setImportsTotal(groupedList.reduce((s, g) => s + Number(g.total_amount || 0), 0));
      } catch (err) {
        // don't block expense loading on import errors
        console.error('Không tải �ược nhập kho cho mùa vụ:', err);
        setProductImports([]);
        setImportsTotal(0);
      }
    } catch (err) {
      pushToast({
        title: "Th�t b�i",
        message: err?.response?.data?.message || 'Không tải �ược chi phí theo mùa vụ',
        type: "error"
      });
    }
  };
  const refreshExpenseCategories = async () => {
    const categoriesRes = await expenseService.getExpenseCategories();
    setExpenseCategories(categoriesRes?.data?.data || []);
  };
  const totalsByCategory = useMemo(() => {
    return expenseCategories.map(category => {
      const id = category.category_id || category.id;
      const name = category.category_name || category.name;
      const categoryExpenses = expenses.filter(item => String(item.category_id) === String(id));
      return {
        id,
        name,
        total: categoryExpenses.reduce((sum, item) => sum + Number(item.amount || 0), 0),
        count: categoryExpenses.length
      };
    });
  }, [expenses, expenseCategories]);
  const handleChange = (field, value) => {
    setForm(prev => {
      const updated = {
        ...prev,
        [field]: value
      };
      // Auto-detect season when expense_date changes
      if (field === 'expense_date' && value) {
        const matchedSeason = seasons.find(season => {
          const startDate = season.start_date ? new Date(season.start_date) : null;
          const endDate = season.actual_harvest ? new Date(season.actual_harvest) : season.expected_harvest ? new Date(season.expected_harvest) : null;
          const expenseDate = new Date(value);
          if (!startDate) return false;
          if (startDate > expenseDate) return false;
          if (endDate && endDate < expenseDate) return false;
          return true;
        });
        if (matchedSeason) {
          updated.season_id = String(matchedSeason.season_id);
        }
      }
      return updated;
    });
  };
  const handleSubmit = async event => {
    event.preventDefault();
    if (!form.season_id) {
      pushToast({
        title: "Th�t b�i",
        message: 'Vui lòng chọn mùa vụ',
        type: "error"
      });
      return;
    }
    if (!form.category_id) {
      pushToast({
        title: "Th�t b�i",
        message: 'Vui lòng chọn loại chi phí',
        type: "error"
      });
      return;
    }
    if (!form.amount || Number(form.amount) <= 0) {
      pushToast({
        title: "Th�t b�i",
        message: 'S� tiền phải l�:n hơn 0',
        type: "error"
      });
      return;
    }
    try {
      setSaving(true);
      await expenseService.createExpense({
        seasonId: Number(form.season_id),
        categoryId: Number(form.category_id),
        amount: Number(form.amount),
        expenseDate: form.expense_date || null,
        note: form.note.trim()
      });
      pushToast({
        title: "Th�nh c�ng",
        message: 'Đã ghi nhận chi phí thành công',
        type: "success"
      });
      setShowModal(false);
      setForm({
        ...emptyForm,
        season_id: String(selectedSeasonId)
      });
      if (selectedSeasonId) {
        await fetchSeasonData(selectedSeasonId);
      }
    } catch (err) {
      pushToast({
        title: "Th�t b�i",
        message: err?.response?.data?.message || 'Không lưu �ược chi phí',
        type: "error"
      });
    } finally {
      setSaving(false);
    }
  };
  const handleCreateCategory = async event => {
    event.preventDefault();
    setCategoryError('');
    setCategorySuccess('');
    if (!categoryName.trim()) {
      setCategoryError('Vui lòng nhập tên danh mục');
      return;
    }
    try {
      setCategorySaving(true);
      const res = await expenseService.createExpenseCategory({
        categoryName: categoryName.trim()
      });
      await refreshExpenseCategories();
      const newCategory = res?.data?.data;
      if (newCategory?.category_id) {
        setForm(prev => ({
          ...prev,
          category_id: String(newCategory.category_id)
        }));
      }
      setCategorySuccess('Đã tạo danh mục chi phí');
      setCategoryName('');
      setShowCategoryModal(false);
    } catch (err) {
      setCategoryError(err?.response?.data?.message || 'Không thỒ tạo danh mục');
    } finally {
      setCategorySaving(false);
    }
  };
  const handleStartEditCategory = category => {
    setEditingCategoryId(category.category_id);
    setEditingCategoryName(category.category_name);
    setCategoryError('');
    setCategorySuccess('');
  };
  const handleCancelEdit = () => {
    setEditingCategoryId(null);
    setEditingCategoryName('');
  };
  const handleSaveEdit = async event => {
    event?.preventDefault();
    if (!editingCategoryName.trim()) {
      setCategoryError('Vui lòng nhập tên danh mục');
      return;
    }
    try {
      setCategorySaving(true);
      await expenseService.updateExpenseCategory(editingCategoryId, {
        categoryName: editingCategoryName.trim()
      });
      await refreshExpenseCategories();
      setCategorySuccess('Đã cập nhật danh mục');
      setEditingCategoryId(null);
      setEditingCategoryName('');
    } catch (err) {
      setCategoryError(err?.response?.data?.message || 'Không thỒ cập nhật danh mục');
    } finally {
      setCategorySaving(false);
    }
  };
  const handleDeleteCategory = async categoryId => {
    if (!window.confirm('Bạn có chắc mu�n xoá danh mục này?')) return;
    try {
      setCategorySaving(true);
      await expenseService.deleteExpenseCategory(categoryId);
      await refreshExpenseCategories();
      setCategorySuccess('Đã xoá danh mục');
    } catch (err) {
      setCategoryError(err?.response?.data?.message || 'Không thỒ xoá danh mục');
    } finally {
      setCategorySaving(false);
    }
  };
  if (loading) {
    return <div className="dashboard">
        <div className="flex-center accountant-expenses-loading">
          <div className="spinner" />
        </div>
      </div>;
  }
  return <div className="dashboard">
      <div className="dashboard-header">
        <h1>�x� Quản lý chi phí (Kế toán)</h1>
        <p>Nhập chi phí và quản lý ghi chép tài chính</p>
      </div>

      <div className="accountant-expenses-toolbar">
        <div className="accountant-expenses-season-filter">
          <label className="accountant-expenses-label">Chọn mùa vụ</label>
          <select value={selectedSeasonId} onChange={e => setSelectedSeasonId(e.target.value)} className="accountant-expenses-select">
            {seasonOptions.map(season => <option key={season.id} value={season.id}>
                {season.label}
              </option>)}
          </select>
        </div>

        <div className="accountant-expenses-actions">
          <button className="btn btn-primary" onClick={() => {
          setForm(prev => ({
            ...prev,
            season_id: String(selectedSeasonId)
          }));
          setShowModal(true);
        }}>
            �~" Ghi nhận chi phí
          </button>
        </div>

        {/* Add-category moved into expense modal */}
      </div>

      <div className="stats-grid accountant-expenses-stats-row">
        <div className="stat-card">
          <div className="stat-icon stat-icon-blue">�x�</div>
          <div className="stat-content">
            <p className="stat-label">Mùa vụ</p>
            <p className="stat-value accountant-expenses-stat-value">{getSeasonLabel(currentSeason || seasonSummary)}</p>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon stat-icon-green">�x�</div>
          <div className="stat-content">
            <p className="stat-label">T�"ng chi phí (bao g�m nhập kho)</p>
            <p className="stat-value">{formatCurrency(Number(seasonSummary.total_expense || 0) + Number(importsTotal || 0))}</p>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon stat-icon-yellow">�x��</div>
          <div className="stat-content">
            <p className="stat-label">S� dòng chi phí</p>
            <p className="stat-value">{expenses.length}</p>
          </div>
        </div>
      </div>

      <div className="stats-grid accountant-expenses-stats-row">
        {totalsByCategory.map(category => <div key={category.id} className="stat-card">
            <div className="stat-icon stat-icon-gray">�x�</div>
            <div className="stat-content">
              <p className="stat-label">{category.name}</p>
              <p className="stat-value accountant-expenses-stat-value">{formatCurrency(category.total)}</p>
              <p className="accountant-expenses-subtext">{category.count} khoản</p>
            </div>
          </div>)}
        {/* Show imports as a separate summary category */}
        <div className="stat-card">
          <div className="stat-icon stat-icon-gray">�x�</div>
          <div className="stat-content">
            <p className="stat-label">Nhập kho (t�"ng)</p>
            <p className="stat-value accountant-expenses-stat-value">{formatCurrency(importsTotal)}</p>
            <p className="accountant-expenses-subtext">{productImports.length} sản phẩm</p>
          </div>
        </div>
      </div>

      {/* Imports by product table */}
      <div className="table-container" style={{
      marginTop: 20
    }}>
        <div className="table-header">
          <h2>Chi phí nhập kho theo sản phẩm (Storekeeper)</h2>
        </div>

        <div className="table-wrapper">
          <table>
            <thead>
              <tr>
                <th>Mã SP</th>
                <th>Sản phẩm</th>
                <th>T�"ng s� lượng</th>
                <th>T�"ng tiền</th>
              </tr>
            </thead>
            <tbody>
              {productImports.length > 0 ? productImports.map(it => <tr key={it.product_id}>
                    <td>{it.product_code}</td>
                    <td>{it.product_name}</td>
                    <td>{Number(it.total_quantity || 0).toLocaleString('vi-VN')}</td>
                    <td><strong>{formatCurrency(it.total_amount)}</strong></td>
                  </tr>) : <tr>
                  <td colSpan="4" className="accountant-expenses-empty-cell">Chưa có dữ li�!u nhập kho cho mùa vụ này</td>
                </tr>}
            </tbody>
          </table>
        </div>
      </div>
      <div className="table-container">
        <div className="table-header">
          <h2>Danh sách chi phí theo mùa vụ</h2>
        </div>

        <div className="table-wrapper">
          <table>
            <thead>
              <tr>
                <th>Ngày chi</th>
                <th>Danh mục</th>
                <th>S� tiền</th>
                <th>Ghi chú</th>
                <th>Người nhập</th>
              </tr>
            </thead>
            <tbody>
              {expenses.length > 0 ? expenses.map(expense => <tr key={expense.expense_id}>
                    <td>{formatDate(expense.expense_date)}</td>
                    <td>{expense.category_name || '-'}</td>
                    <td><strong>{formatCurrency(expense.amount)}</strong></td>
                    <td className="accountant-expenses-note-cell">{expense.note || '-'}</td>
                    <td>{expense.created_by_name || expense.created_by_username || '-'}</td>
                  </tr>) : <tr>
                  <td colSpan="5" className="accountant-expenses-empty-cell">
                    Chưa có khoản chi nào trong mùa vụ này
                  </td>
                </tr>}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && <div className="modal" onClick={() => setShowModal(false)}>
          <div className="modal-content" onClick={e => e.stopPropagation()}>
            <h2>�x� Ghi nhận chi phí</h2>
            <form onSubmit={handleSubmit}>
              <div className="form-group">
                <label>Mùa vụ *</label>
                <select value={form.season_id} onChange={e => handleChange('season_id', e.target.value)} required>
                  <option value="">Chọn mùa vụ</option>
                  {seasonOptions.map(season => <option key={season.id} value={season.id}>
                      {season.label}
                    </option>)}
                </select>
              </div>

              <div className="form-group">
                <label>Loại chi phí *</label>
                <div className="accountant-expenses-inline-row">
                  <select value={form.category_id} onChange={e => handleChange('category_id', e.target.value)} required className="accountant-expenses-grow">
                    <option value="">Chọn loại chi phí</option>
                    {expenseCategories.map(category => <option key={category.category_id} value={category.category_id}>
                        {category.category_name}
                      </option>)}
                  </select>
                  <button type="button" className="btn btn-secondary" className="accountant-expenses-add-btn" onClick={() => setShowCategoryModal(true)}>
                    �~"
                  </button>
                </div>
              </div>

              <div className="form-row accountant-expenses-form-row">
                <div className="form-group">
                  <label>S� tiền (�) *</label>
                  <input type="number" min="0" step="0.01" value={form.amount} onChange={e => handleChange('amount', e.target.value)} required />
                </div>

                <div className="form-group">
                  <label>Ngày chi</label>
                  <input type="date" value={form.expense_date} onChange={e => handleChange('expense_date', e.target.value)} />
                </div>
              </div>

              <div className="form-group">
                <label>Ghi chú</label>
                <textarea value={form.note} onChange={e => handleChange('note', e.target.value)} placeholder="Ví dụ: Mua thức Ēn cho ao A1, hóa �ơn �i�!n tháng 5..." />
              </div>

              <div className="accountant-expenses-actions-row">
                <button type="submit" className="btn btn-primary accountant-expenses-flex-btn" disabled={saving}>
                  {saving ? 'Đang lưu...' : 'Lưu chi phí'}
                </button>
                <button type="button" className="btn btn-secondary" className="accountant-expenses-flex-btn" onClick={() => setShowModal(false)}>
                  Hủy
                </button>
              </div>
            </form>
          </div>
        </div>}

      {showCategoryModal && <div className="modal" onClick={() => setShowCategoryModal(false)}>
          <div className="modal-content" onClick={e => e.stopPropagation()}>
            <h2>�x� Quản lý danh mục chi phí</h2>


            <div className="accountant-expenses-category-list">
              {expenseCategories.length === 0 && <div>Chưa có danh mục nào.</div>}
              {expenseCategories.map(cat => <div key={cat.category_id} className="accountant-expenses-category-item">
                  {editingCategoryId === cat.category_id ? <form className="accountant-expenses-category-edit" onSubmit={handleSaveEdit}>
                      <input value={editingCategoryName} onChange={e => setEditingCategoryName(e.target.value)} className="accountant-expenses-grow" required />
                      <button type="submit" className="btn btn-primary" disabled={categorySaving}>Lưu</button>
                      <button type="button" className="btn btn-secondary" onClick={handleCancelEdit}>Hủy</button>
                    </form> : <>
                      <div className="accountant-expenses-grow">{cat.category_name}</div>
                      <button type="button" className="btn" onClick={() => handleStartEditCategory(cat)}>Sửa</button>
                      <button type="button" className="btn btn-danger" onClick={() => handleDeleteCategory(cat.category_id)}>Xoá</button>
                    </>}
                </div>)}
            </div>

            <hr className="accountant-expenses-divider" />

            <h3>�~" Thêm danh mục m�:i</h3>
            <form onSubmit={handleCreateCategory}>
              <div className="form-group">
                <label>Tên danh mục *</label>
                <input type="text" value={categoryName} onChange={e => setCategoryName(e.target.value)} placeholder="Ví dụ: Thức Ēn, Thu�c, Đi�!n, Bảo trì..." required />
              </div>

              <div className="accountant-expenses-actions-row">
                <button type="submit" className="btn btn-primary accountant-expenses-flex-btn" disabled={categorySaving}>
                  {categorySaving ? 'Đang lưu...' : 'Lưu danh mục'}
                </button>
                <button type="button" className="btn btn-secondary" className="accountant-expenses-flex-btn" onClick={() => setShowCategoryModal(false)}>
                  Đóng
                </button>
              </div>
            </form>
          </div>
        </div>}
    </div>;
};
export default AccountantExpenses;
